import os

def read_last_line_efficiently(filepath, encoding='utf-8'):
    with open(filepath, 'rb') as f:
        f.seek(0, os.SEEK_END)
        file_size = f.tell()

        if file_size == 0:
            return ""

        block_size = 4096  # 4KB'lık parçalar halinde oku

        current_pos = file_size
        buffer = b''

        while current_pos > 0:
            read_start = max(0, current_pos - block_size)
            f.seek(read_start)
            chunk = f.read(current_pos - read_start)

            buffer = chunk + buffer # Yeni parçayı tamponun başına ekle

            last_newline_idx = buffer.rfind(b'\n')

            if last_newline_idx != -1:
                potential_line = buffer[last_newline_idx+1:]
                stripped_line = potential_line.strip(b'\r\n')

                if stripped_line:
                    return stripped_line.decode(encoding)
                else:
                    # Sondaki boş satırı veya birden fazla yeni satırı yoksay
                    buffer = buffer[:last_newline_idx]

            current_pos = read_start

            if current_pos == 0:
                # Dosyanın başına ulaşıldı, tüm dosya içeriği artık tamponda
                return buffer.strip(b'\r\n').decode(encoding)

        return ""
